import sqlite3, json, glob
c = sqlite3.connect('db/analytics.sqlite')
reg = dict(c.execute('select device_id, tenant_id from devices'))
mismatch = {}
for f in glob.glob('metrics/telemetry/*.jsonl'):
    for line in open(f):
        line=line.strip()
        if not line: continue
        o=json.loads(line)
        if reg.get(o['device_id']) != o['tenant_id']:
            mismatch.setdefault(o['device_id'], set()).add((reg.get(o['device_id']), o['tenant_id']))
print('devices with tenant mismatch between registry and telemetry:', len(mismatch))
for k,v in list(mismatch.items())[:10]: print(k, v)
